"use client";

import { useState, useEffect, useRef } from "react";
import { Message, Recipe } from "@/types/chat";
import { ChatMessage } from "@/components/ChatMessage";
import { ChatInput } from "@/components/ChatInput";
import { recognizeIngredients, searchRecipes } from "@/lib/api";
import { UtensilsCrossed } from "lucide-react";

export default function Home() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [processing, setProcessing] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // 滚动到底部
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // 添加消息
  const addMessage = (message: Omit<Message, "id" | "timestamp">) => {
    const newMessage: Message = {
      ...message,
      id: Date.now().toString(),
      timestamp: Date.now(),
    };
    setMessages((prev) => [...prev, newMessage]);
    return newMessage;
  };

  // 更新消息
  const updateMessage = (id: string, updates: Partial<Message>) => {
    setMessages((prev) =>
      prev.map((msg) => (msg.id === id ? { ...msg, ...updates } : msg))
    );
  };

  // 处理发送消息
  const handleSend = async (text: string, image?: string) => {
    if (processing) return;

    // 添加用户消息
    addMessage({
      role: "user",
      content: text || "上传了一张食材图片",
      image,
    });

    setProcessing(true);

    try {
      // 如果有图片，先识别食材
      if (image) {
        // 添加加载消息
        const loadingId = addMessage({
          role: "assistant",
          content: "正在识别图片中的食材...",
          loading: true,
        }).id;

        const result = await recognizeIngredients(image);

        if (result.success && result.ingredients.length > 0) {
          updateMessage(loadingId, {
            content: `已识别出食材：${result.ingredients.join("、")}${result.notes ? `\n\n备注：${result.notes}` : ""}`,
            loading: false,
          });

          // 自动搜索食谱
          await searchAndShowRecipes(result.ingredients);
        } else {
          updateMessage(loadingId, {
            content: "未能识别出明确的食材，请尝试上传更清晰的图片。",
            loading: false,
          });
        }
      } else if (text) {
        // 纯文本消息，简单回复
        addMessage({
          role: "assistant",
          content: "请上传食材图片，我会帮你识别并推荐食谱。",
        });
      }
    } catch (error) {
      console.error("处理失败:", error);
      addMessage({
        role: "assistant",
        content: "处理失败，请稍后重试。",
      });
    } finally {
      setProcessing(false);
    }
  };

  // 搜索并显示食谱
  const searchAndShowRecipes = async (ingredients: string[]) => {
    const loadingId = addMessage({
      role: "assistant",
      content: `正在为您搜索 "${ingredients.join("、")}" 相关的食谱...`,
      loading: true,
    }).id;

    const result = await searchRecipes(ingredients);

    if (result.success && result.recipes.length > 0) {
      updateMessage(loadingId, {
        content: `为您找到 ${result.recipes.length} 个食谱推荐：`,
        loading: false,
        recipes: result.recipes,
      });
    } else {
      updateMessage(loadingId, {
        content: "未能找到匹配的食谱，您可以尝试上传不同的食材图片。",
        loading: false,
      });
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50">
      {/* 标题栏 */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center gap-3">
        <UtensilsCrossed className="text-orange-500" size={24} />
        <div>
          <h1 className="text-xl font-semibold">AI 智能食谱推荐</h1>
          <p className="text-sm text-gray-500">上传食材图片，获取个性化食谱推荐</p>
        </div>
      </header>

      {/* 聊天区域 */}
      <div className="flex-1 overflow-y-auto p-4">
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-gray-400">
            <UtensilsCrossed size={64} className="mb-4 opacity-50" />
            <p className="text-lg">上传食材图片开始吧</p>
            <p className="text-sm mt-2">我会帮您识别食材并推荐食谱</p>
          </div>
        ) : (
          <div className="max-w-3xl mx-auto">
            {messages.map((message,index) => (
              <ChatMessage key={`${message.id}-recipe-${index}`} message={message} />
            ))}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      {/* 输入区域 */}
      <ChatInput onSend={handleSend} disabled={processing} />
    </div>
  );
}
