/**
 * API 调用封装
 */
const API_BASE = "http://localhost:8001";

/**
 * 获取 OSS 预签名上传 URL
 */
export async function getOssPresignUrl(filename: string): Promise<string> {
  const response = await fetch(`${API_BASE}/api/v1/oss/presign?filename=${filename}`);
  if (!response.ok) {
    throw new Error("获取上传 URL 失败");
  }
  const data = await response.text();
  return data;
}

/**
 * 上传图片到 OSS
 */
export async function uploadImageToOss(file: File): Promise<string> {
  // 生成文件名
  const ext = file.name.split(".").pop() || "jpg";
  const filename = `${Date.now()}.${ext}`;

  // 获取预签名 URL
  const presignUrl = await getOssPresignUrl(filename);

  // 上传图片
  const response = await fetch(presignUrl, {
    method: "PUT",
    body: file,
  });

  if (!response.ok) {
    throw new Error("图片上传失败");
  }

  // 返回 OSS 文件的公网访问地址
  // 注意：这里需要根据你的 OSS 配置调整 URL 格式
  const ossBucket = process.env.NEXT_PUBLIC_OSS_BUCKET || "your-bucket";
  const ossRegion = "cn-beijing";
  return `https://${ossBucket}.${ossRegion}.aliyuncs.com/${filename}`;
}

/**
 * 流式聊天
 */
export async function streamChat(
  message: string,
  fileUrls?: string,
  onChunk: (chunk: string) => void,
  onError?: (error: Error) => void,
  onComplete?: () => void
): Promise<void> {
  try {
    const url = new URL(`${API_BASE}/api/v1/chat/stream`);
    url.searchParams.append("message", message);
    if (fileUrls) {
      url.searchParams.append("file_urls", fileUrls);
    }

    const response = await fetch(url.toString(), {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
    });

    if (!response.ok) {
      throw new Error("请求失败");
    }

    const reader = response.body?.getReader();
    if (!reader) {
      throw new Error("无法读取响应流");
    }

    const decoder = new TextDecoder();

    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        onComplete?.();
        break;
      }

      const chunk = decoder.decode(value, { stream: true });
      onChunk(chunk);
    }
  } catch (error) {
    onError?.(error as Error);
  }
}